SELECT 
FROM TB_CONTRACT A
LEFT JOIN TB_CONSTRUCTION B ON A.CONSTRUCTION_IDX = B.id

	A.isDel = 0

		AND A.CONSTRUCTION_IDX = #{param.constructionIdx}


		AND A.STATUS = #{param.status}


		AND B.name LIKE '%${param.searchWord}%'


ORDER BY A.CONTRACT_IDX DESC
LIMIT #{param.pageSize} OFFSET #{param.startRow}

